def process_graph(graph_data):

    super_blocks = [node for node in graph_data.nodes if 'EK_SUPERBLOCK' in graph_data.nodes[node]['type']]
    bandwidths = []

    for super_block in super_blocks:
        packet_switches = [node for node in graph_data.successors(super_block) if 'EK_PACKET_SWITCH' in graph_data.nodes[node]['type']]
        total_bandwidth = 0

        for packet_switch in packet_switches:
            ports = [node for node in graph_data.successors(packet_switch) if 'EK_PORT' in graph_data.nodes[node]['type']]

            for port in ports:
                total_bandwidth += graph_data.nodes[port]['physical_capacity_bps'] / 1e6  # Convert to Mbps

        bandwidths.append([super_block, total_bandwidth])

    return_object = {
        'type': 'table',
        'data': [['SUPERBLOCK', 'Bandwidth']] + bandwidths
    }

    return return_object

def process_graph(graph_data):
    # Remove packet switch 'ju1.a1.m1.s2c4' from Chassis c4
    packet_switch_to_remove = 'ju1.a1.m1.s2c4'
    chassis_to_balance = 'c4'
    if packet_switch_to_remove in graph_data.nodes():
        graph_data.remove_node(packet_switch_to_remove)

    # Find all Chassis nodes
    chassis_nodes = [n for n, attr in graph_data.nodes(data=True) if 'EK_CHASSIS' in attr['type']]

    # Calculate the total capacity for each Chassis
    chassis_capacity = {}
    for chassis in chassis_nodes:
        packet_switches = [n for n in graph_data.neighbors(chassis) if 'EK_PACKET_SWITCH' in graph_data.nodes[n]['type']]
        total_capacity = 0
        for packet_switch in packet_switches:
            ports = [n for n in graph_data.neighbors(packet_switch) if 'EK_PORT' in graph_data.nodes[n]['type']]
            for port in ports:
                total_capacity += graph_data.nodes[port]['physical_capacity_bps']
        chassis_capacity[chassis] = total_capacity

    # Calculate the average capacity
    average_capacity = sum(chassis_capacity.values()) / len(chassis_capacity)

    # Balance the capacity between Chassis
    for chassis in chassis_nodes:
        if chassis_capacity[chassis] < average_capacity:
            extra_capacity = average_capacity - chassis_capacity[chassis]
            # Find a packet switch from another chassis with enough capacity
            for other_chassis in chassis_nodes:
                if other_chassis != chassis:
                    other_packet_switches = [n for n in graph_data.neighbors(other_chassis) if 'EK_PACKET_SWITCH' in graph_data.nodes[n]['type']]
                    for packet_switch in other_packet_switches:
                        ports = [n for n in graph_data.neighbors(packet_switch) if 'EK_PORT' in graph_data.nodes[n]['type']]
                        packet_switch_capacity = sum(graph_data.nodes[port]['physical_capacity_bps'] for port in ports)
                        if packet_switch_capacity >= extra_capacity:
                            # Move the packet switch to the current chassis
                            graph_data.remove_edge(other_chassis, packet_switch)
                            graph_data.add_edge(chassis, packet_switch, type='RK_CONTAINS')
                            break

    return {'type': 'graph', 'data': graph_data}
